package cn.mtplayer.tv;
import android.content.Intent;import android.os.Bundle;import android.view.ViewGroup;import android.widget.Button;import android.widget.GridLayout;import android.widget.ImageView;import android.widget.LinearLayout;import android.widget.ScrollView;import android.widget.TextView;import androidx.appcompat.app.AppCompatActivity;import androidx.media3.common.util.UnstableApi;import com.bumptech.glide.Glide;import java.util.List;import java.util.concurrent.ExecutorService;import java.util.concurrent.Executors;import cn.mtplayer.core.model.Episode;import cn.mtplayer.core.model.MediaDetail;import cn.mtplayer.core.model.MediaItem;import cn.mtplayer.core.model.PlayLine;import cn.mtplayer.core.model.Site;
@UnstableApi public final class TvDetailActivity extends AppCompatActivity{private final ExecutorService executor=Executors.newSingleThreadExecutor();private LinearLayout root;private MediaItem item;private MediaDetail detail;private TvLibrary library;private int lineIndex=0;private Episode selected;
@Override protected void onCreate(Bundle b){super.onCreate(b);item=(MediaItem)getIntent().getSerializableExtra("item");library=new TvLibrary(this);ScrollView s=new ScrollView(this);root=TvUi.column(this);s.addView(root);setContentView(s);root.addView(TvUi.title(this,item==null?"影片详情":item.name,34),TvUi.matchWrap());root.addView(TvUi.text(this,"正在检查播放接口…"),TvUi.matchWrap());load();}@Override protected void onDestroy(){executor.shutdownNow();super.onDestroy();}
private void load(){executor.execute(()->{try{List<Site> sites=TvServices.configurations.enabledSites();Site site=null;for(Site v:sites)if(v.key.equals(item.siteKey)){site=v;break;}if(site==null)throw new IllegalStateException("播放接口已停用");detail=TvServices.catalogue.detail(site,item.id);runOnUiThread(this::render);}catch(Exception e){runOnUiThread(()->root.addView(TvUi.text(this,"加载失败："+(e.getMessage()==null?"未知错误":e.getMessage())),TvUi.matchWrap()));}});}
private void render(){root.removeAllViews();LinearLayout hero=new LinearLayout(this);ImageView poster=new ImageView(this);poster.setScaleType(ImageView.ScaleType.CENTER_CROP);Glide.with(this).load(detail.item.poster).into(poster);hero.addView(poster,new LinearLayout.LayoutParams(TvUi.dp(this,300),TvUi.dp(this,430)));LinearLayout info=TvUi.column(this);TextView type=TvUi.text(this,detail.item.type+" · "+detail.item.year+" · "+detail.item.siteName);type.setTextColor(TvUi.RED);info.addView(type,TvUi.matchWrap());info.addView(TvUi.title(this,detail.item.name,38),TvUi.matchWrap());info.addView(TvUi.text(this,"导演："+safe(detail.director)+"\n主演："+safe(detail.actor)+"\n\n"+safe(detail.content)),TvUi.matchWrap());LinearLayout actions=new LinearLayout(this);Button play=TvUi.button(this,"▶ 播放所选集",true),fav=TvUi.button(this,library.isFavorite(item)?"♥ 已收藏":"♡ 加入收藏",false);actions.addView(play,new LinearLayout.LayoutParams(TvUi.dp(this,230),TvUi.dp(this,64)));actions.addView(fav,new LinearLayout.LayoutParams(TvUi.dp(this,210),TvUi.dp(this,64)));info.addView(actions,TvUi.matchWrap());hero.addView(info,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(hero,TvUi.matchWrap());fav.setOnClickListener(v->{library.toggle(item);fav.setText(library.isFavorite(item)?"♥ 已收藏":"♡ 加入收藏");});root.addView(TvUi.title(this,"播放接口",22),TvUi.matchWrap());TextView source=TvUi.text(this,detail.item.siteName+"（已确认包含该影片）");source.setTextColor(TvUi.TEXT);source.setPadding(TvUi.dp(this,16),TvUi.dp(this,14),TvUi.dp(this,16),TvUi.dp(this,14));TvUi.style(source,TvUi.HIGH,false);root.addView(source,TvUi.matchWrap());root.addView(TvUi.title(this,"播放线路",22),TvUi.matchWrap());LinearLayout lines=new LinearLayout(this);root.addView(lines,TvUi.matchWrap());GridLayout episodes=new GridLayout(this);episodes.setColumnCount(6);root.addView(TvUi.title(this,"选择剧集",24),TvUi.matchWrap());root.addView(episodes,TvUi.matchWrap());Runnable refresh=()->renderEpisodes(episodes);for(int i=0;i<detail.lines.size();i++){PlayLine line=detail.lines.get(i);Button b=TvUi.button(this,line.name,i==0);int index=i;b.setOnClickListener(v->{lineIndex=index;selected=detail.lines.get(index).episodes.isEmpty()?null:detail.lines.get(index).episodes.get(0);refresh.run();});lines.addView(b,new LinearLayout.LayoutParams(TvUi.dp(this,180),TvUi.dp(this,58)));}if(!detail.lines.isEmpty()&&!detail.lines.get(0).episodes.isEmpty())selected=detail.lines.get(0).episodes.get(0);refresh.run();play.setOnClickListener(v->{if(selected==null)return;library.record(item);Intent x=new Intent(this,TvPlayerActivity.class);x.putExtra("url",selected.url);x.putExtra("title",detail.item.name+" · "+selected.name);x.putExtra("mediaKey",item.siteKey+":"+item.id);startActivity(x);});}
private void renderEpisodes(GridLayout grid){grid.removeAllViews();if(detail.lines.isEmpty())return;for(Episode e:detail.lines.get(lineIndex).episodes){Button b=TvUi.button(this,e.name,e==selected);b.setTag(e);GridLayout.LayoutParams p=new GridLayout.LayoutParams();p.width=0;p.height=TvUi.dp(this,60);p.columnSpec=GridLayout.spec(GridLayout.UNDEFINED,1f);p.setMargins(TvUi.dp(this,5),TvUi.dp(this,5),TvUi.dp(this,5),TvUi.dp(this,5));b.setLayoutParams(p);b.setOnClickListener(v->{selected=e;for(int i=0;i<grid.getChildCount();i++){Button x=(Button)grid.getChildAt(i);TvUi.style(x,x.getTag()==e?TvUi.RED:TvUi.HIGH,x.hasFocus());}});grid.addView(b);}}
private static String safe(String s){return s==null||s.isBlank()?"暂无":s;}}
